import React, { useState } from 'react';
import { Save, Trophy, Scale, Ruler, Calendar, Star, Flame } from 'lucide-react';

const Profile = ({ user, setUser }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    username: user.username,
    email: user.email,
    height: user.height,
    weight: user.weight,
    age: user.age,
    gender: user.gender,
    weeklyGoal: user.weeklyGoal,
    dailyCalorieGoal: user.dailyCalorieGoal
  });

  // BMI Calculation (Fixed syntax)
  const heightInM = formData.height / 100;
  const bmi = parseFloat((formData.weight / (heightInM * heightInM)).toFixed(1));
  
  const getBMICategory = (bmi) => {
    if (bmi < 18.5) return { label: 'Underweight', color: '#f59e0b' };
    if (bmi < 24.9) return { label: 'Normal', color: '#10b981' };
    if (bmi < 29.9) return { label: 'Overweight', color: '#f59e0b' };
    return { label: 'Obese', color: '#ef4444' };
  };

  const bmiCategory = getBMICategory(bmi);

  const handleSave = () => {
    setUser({ ...user, ...formData });
    setIsEditing(false);
    alert('Profile updated successfully! ✓');
  };

  const allBadges = [
    { name: 'First Workout', icon: '🎯', description: 'Complete your first workout' },
    { name: '7 Day Streak', icon: '🔥', description: 'Work out 7 days in a row' },
    { name: '30 Day Streak', icon: '💪', description: 'Work out 30 days in a row' },
    { name: '50 Club', icon: '🏆', description: 'Complete 50 workouts' },
    { name: 'Calorie Crusher', icon: '⚡', description: 'Burn 10,000 calories' },
    { name: 'Early Bird', icon: '🌅', description: 'Complete 5 workouts before 7AM' },
  ];

  // Check if user has badge
  const hasBadge = (badgeName) => {
    return user.badges && user.badges.includes(badgeName);
  };

  return (
    <div className="profile">
      <h1 className="page-title">Profile</h1>

      <div className="profile-grid">
        {/* Profile Info Card */}
        <div className="profile-card">
          <div className="profile-header">
            <div className="profile-avatar">
              {formData.username.charAt(0)}
            </div>
            <div className="profile-info">
              <h3>{user.username}</h3>
              <p>{user.email}</p>
            </div>
            <button 
              className="btn-secondary" 
              onClick={() => isEditing ? handleSave() : setIsEditing(true)}
              style={{ marginLeft: 'auto' }}
            >
              {isEditing ? (
                <><Save size={16} style={{ marginRight: '6px' }} /> Save</>
              ) : 'Edit Profile'}
            </button>
          </div>

          <div className="stats-row">
            <div className="stat-item">
              <h4><Scale size={16} style={{ marginRight: '6px' }} /> Weight</h4>
              {isEditing ? (
                <input
                  type="number"
                  className="form-input"
                  value={formData.weight}
                  onChange={(e) => setFormData({ ...formData, weight: parseFloat(e.target.value) })}
                  style={{ marginTop: '8px' }}
                />
              ) : (
                <p style={{ fontSize: '1.5rem', fontWeight: '700' }}>{user.weight} kg</p>
              )}
            </div>
            <div className="stat-item">
              <h4><Ruler size={16} style={{ marginRight: '6px' }} /> Height</h4>
              {isEditing ? (
                <input
                  type="number"
                  className="form-input"
                  value={formData.height}
                  onChange={(e) => setFormData({ ...formData, height: parseFloat(e.target.value) })}
                  style={{ marginTop: '8px' }}
                />
              ) : (
                <p style={{ fontSize: '1.5rem', fontWeight: '700' }}>{user.height} cm</p>
              )}
            </div>
            <div className="stat-item">
              <h4><Calendar size={16} style={{ marginRight: '6px' }} /> Age</h4>
              {isEditing ? (
                <input
                  type="number"
                  className="form-input"
                  value={formData.age}
                  onChange={(e) => setFormData({ ...formData, age: parseInt(e.target.value) })}
                  style={{ marginTop: '8px' }}
                />
              ) : (
                <p style={{ fontSize: '1.5rem', fontWeight: '700' }}>{user.age} years</p>
              )}
            </div>
            <div className="stat-item">
              <h4><Star size={16} style={{ marginRight: '6px' }} /> Weekly Goal</h4>
              {isEditing ? (
                <input
                  type="number"
                  className="form-input"
                  value={formData.weeklyGoal}
                  onChange={(e) => setFormData({ ...formData, weeklyGoal: parseInt(e.target.value) })}
                  style={{ marginTop: '8px' }}
                />
              ) : (
                <p style={{ fontSize: '1.5rem', fontWeight: '700' }}>{user.weeklyGoal} workouts</p>
              )}
            </div>
          </div>

          {/* BMI Calculator */}
          <div className="bmi-section">
            <h3 style={{ marginBottom: '16px' }}><Scale size={18} style={{ marginRight: '8px' }} />BMI Calculator</h3>
            <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
              <div style={{ flex: 1 }}>
                {isEditing && (
                  <>
                    <input
                      type="range"
                      min="40"
                      max="150"
                      value={formData.weight}
                      onChange={(e) => setFormData({ ...formData, weight: parseFloat(e.target.value) })}
                      style={{ width: '100%' }}
                    />
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '8px', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                      <span>40 kg</span>
                      <span>150 kg</span>
                    </div>
                  </>
                )}
              </div>
              <div className="bmi-result" style={{ 
                background: `${bmiCategory.color}20`, 
                border: `1px solid ${bmiCategory.color}`,
                padding: '20px',
                borderRadius: '12px',
                textAlign: 'center',
                minWidth: '120px'
              }}>
                <div className="bmi-value" style={{ color: bmiCategory.color, fontSize: '2.5rem', fontWeight: '700' }}>{bmi}</div>
                <div className="bmi-category" style={{ color: bmiCategory.color, fontSize: '1.1rem', fontWeight: '500' }}>{bmiCategory.label}</div>
              </div>
            </div>
          </div>
        </div>

        {/* Badges Card */}
        <div className="profile-card">
          <h3 style={{ marginBottom: '20px' }}><Trophy size={20} style={{ marginRight: '8px' }} />Achievements</h3>
          
          <div style={{ marginBottom: '24px' }}>
            <h4 style={{ color: 'var(--text-secondary)', marginBottom: '12px', fontSize: '0.9rem' }}>YOUR STATS</h4>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <div style={{ padding: '16px', background: 'var(--bg-input)', borderRadius: '8px' }}>
                <div style={{ fontSize: '1.5rem', fontWeight: '700' }}>{user.totalWorkouts || 0}</div>
                <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>Total Workouts</div>
              </div>
              <div style={{ padding: '16px', background: 'var(--bg-input)', borderRadius: '8px' }}>
                <div style={{ fontSize: '1.5rem', fontWeight: '700' }}>{user.currentStreak || 0}</div>
                <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>Current Streak</div>
              </div>
              <div style={{ padding: '16px', background: 'var(--bg-input)', borderRadius: '8px' }}>
                <div style={{ fontSize: '1.5rem', fontWeight: '700' }}>{user.longestStreak || 0}</div>
                <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>Best Streak</div>
              </div>
              <div style={{ padding: '16px', background: 'var(--bg-input)', borderRadius: '8px' }}>
                <div style={{ fontSize: '1.5rem', fontWeight: '700' }}>{((user.totalCaloriesBurned || 0) / 1000).toFixed(1)}k</div>
                <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>Calories Burned</div>
              </div>
            </div>
          </div>

          <h4 style={{ color: 'var(--text-secondary)', marginBottom: '12px', fontSize: '0.9rem' }}>BADGES EARNED</h4>
          <div className="badges-grid">
            {allBadges.map((badge, index) => {
              const earned = hasBadge(badge.name);
              return (
                <div 
                  className="badge-item" 
                  key={index}
                  style={{ 
                    opacity: earned ? 1 : 0.4,
                    background: earned ? 'rgba(251, 191, 36, 0.1)' : 'var(--bg-input)',
                    borderColor: earned ? 'rgba(251, 191, 36, 0.3)' : 'transparent',
                    padding: '16px',
                    borderRadius: '10px',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '12px'
                  }}
                >
                  <span style={{ fontSize: '1.5rem' }}>{badge.icon}</span>
                  <div>
                    <h4 style={{ color: earned ? '#fbbf24' : 'var(--text-muted)', marginBottom: '4px' }}>{badge.name}</h4>
                    <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{badge.description}</p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
